<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
    margin: 0; padding: 1.5rem; background: #f4f5f7; color: #1c2024;
    max-width: 860px; margin-inline: auto;
  }
  h1 { font-size: 1.4rem; margin: 0 0 1rem; }
  .card {
    background: #fff; border: 1px solid #e2e4e8; border-radius: 10px;
    padding: 1rem 1.25rem; margin-bottom: 1.25rem;
  }
  label { display: block; font-size: 0.78rem; font-weight: 600; margin-bottom: 0.25rem; color: #4a5058; }
  input, select, button { font: inherit; }
  input, select {
    padding: 0.5rem 0.6rem; border: 1px solid #cbd0d6; border-radius: 6px;
    background: #fff; width: 100%;
  }
  .form-grid {
    display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 0.85rem; align-items: end;
  }
  button {
    cursor: pointer; border: none; border-radius: 6px; padding: 0.55rem 0.9rem;
    background: #2f6fed; color: #fff; font-weight: 600;
  }
  button:hover { background: #2a62d4; }
  #form-error { color: #c0362c; font-size: 0.85rem; margin-top: 0.6rem; min-height: 1rem; font-weight: 600; }
  .filters { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 0.85rem; }
  .summary { display: flex; flex-wrap: wrap; gap: 0.6rem; align-items: center; margin-top: 0.5rem; }
  .cat-total {
    background: #eef2fb; border: 1px solid #d5def6; border-radius: 20px;
    padding: 0.3rem 0.7rem; font-size: 0.82rem;
  }
  #total-line { font-size: 1.15rem; font-weight: 700; margin-bottom: 0.5rem; }
  table { width: 100%; border-collapse: collapse; }
  th, td { text-align: left; padding: 0.55rem 0.5rem; border-bottom: 1px solid #eceef1; font-size: 0.9rem; }
  th { font-size: 0.72rem; text-transform: uppercase; letter-spacing: 0.03em; color: #6b727b; }
  td.amt { font-variant-numeric: tabular-nums; font-weight: 600; }
  .exp-del {
    background: #f4d7d5; color: #a2322a; padding: 0.3rem 0.6rem; font-size: 0.8rem;
  }
  .exp-del:hover { background: #eec1bd; }
  .empty { color: #8b929b; font-style: italic; padding: 0.8rem 0.5rem; }
  .cat-badge {
    background: #f0f1f3; border-radius: 5px; padding: 0.1rem 0.45rem; font-size: 0.8rem;
    text-transform: capitalize;
  }
</style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <div class="card">
    <form id="expense-form" novalidate>
      <div class="form-grid">
        <div>
          <label for="amount">Amount</label>
          <input type="number" id="amount" step="0.01" placeholder="0.00">
        </div>
        <div>
          <label for="category">Category</label>
          <select id="category">
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div>
          <label for="date">Date</label>
          <input type="date" id="date">
        </div>
        <div>
          <label for="note">Note (optional)</label>
          <input type="text" id="note" placeholder="e.g. weekly shop">
        </div>
        <div>
          <button type="submit" id="add-expense">Add Expense</button>
        </div>
      </div>
      <div id="form-error"></div>
    </form>
  </div>

  <div class="card">
    <div class="filters">
      <div>
        <label for="filter-category">Filter by category</label>
        <select id="filter-category">
          <option value="all">All</option>
          <option value="groceries">Groceries</option>
          <option value="transport">Transport</option>
          <option value="bills">Bills</option>
          <option value="fun">Fun</option>
        </select>
      </div>
      <div>
        <label for="filter-from">From</label>
        <input type="date" id="filter-from">
      </div>
      <div>
        <label for="filter-to">To</label>
        <input type="date" id="filter-to">
      </div>
    </div>
    <div class="summary">
      <span class="cat-total" data-cat="groceries">groceries: 0.00</span>
      <span class="cat-total" data-cat="transport">transport: 0.00</span>
      <span class="cat-total" data-cat="bills">bills: 0.00</span>
      <span class="cat-total" data-cat="fun">fun: 0.00</span>
    </div>
  </div>

  <div class="card">
    <div id="total-line">Total (visible): <span id="total">0.00</span></div>
    <table>
      <thead>
        <tr><th>Amount</th><th>Category</th><th>Date</th><th>Note</th><th></th></tr>
      </thead>
      <tbody id="expense-list"></tbody>
    </table>
  </div>

<script>
(function () {
  "use strict";

  var CATEGORIES = ["groceries", "transport", "bills", "fun"];
  var STORAGE_KEY = "expense-tracker-v1";

  var expenses = load();

  var form = document.getElementById("expense-form");
  var amountEl = document.getElementById("amount");
  var categoryEl = document.getElementById("category");
  var dateEl = document.getElementById("date");
  var noteEl = document.getElementById("note");
  var errorEl = document.getElementById("form-error");

  var filterCatEl = document.getElementById("filter-category");
  var filterFromEl = document.getElementById("filter-from");
  var filterToEl = document.getElementById("filter-to");

  var listEl = document.getElementById("expense-list");
  var totalEl = document.getElementById("total");

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var parsed = JSON.parse(raw);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (e) { /* ignore quota / disabled storage */ }
  }

  function fmt(n) {
    return (Math.round(n * 100) / 100).toFixed(2);
  }

  function passesFilter(exp) {
    var cat = filterCatEl.value;
    if (cat !== "all" && exp.category !== cat) return false;
    var from = filterFromEl.value;
    var to = filterToEl.value;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  function render() {
    // Newest first: sort by date desc, then by id (insertion) desc.
    var sorted = expenses.slice().sort(function (a, b) {
      if (a.date !== b.date) return a.date < b.date ? 1 : -1;
      return b.id - a.id;
    });

    listEl.innerHTML = "";
    var visibleTotal = 0;
    var catTotals = { groceries: 0, transport: 0, bills: 0, fun: 0 };
    var anyVisible = false;

    sorted.forEach(function (exp) {
      if (!passesFilter(exp)) return;
      anyVisible = true;
      visibleTotal += exp.amount;
      if (catTotals.hasOwnProperty(exp.category)) {
        catTotals[exp.category] += exp.amount;
      }

      var tr = document.createElement("tr");
      tr.className = "expense";

      var amtTd = document.createElement("td");
      amtTd.className = "amt";
      amtTd.textContent = fmt(exp.amount);

      var catTd = document.createElement("td");
      var badge = document.createElement("span");
      badge.className = "cat-badge";
      badge.textContent = exp.category;
      catTd.appendChild(badge);

      var dateTd = document.createElement("td");
      dateTd.textContent = exp.date;

      var noteTd = document.createElement("td");
      noteTd.textContent = exp.note || "";

      var delTd = document.createElement("td");
      var delBtn = document.createElement("button");
      delBtn.type = "button";
      delBtn.className = "exp-del";
      delBtn.textContent = "Delete";
      delBtn.addEventListener("click", function () {
        remove(exp.id);
      });
      delTd.appendChild(delBtn);

      tr.appendChild(amtTd);
      tr.appendChild(catTd);
      tr.appendChild(dateTd);
      tr.appendChild(noteTd);
      tr.appendChild(delTd);
      listEl.appendChild(tr);
    });

    if (!anyVisible) {
      var tr = document.createElement("tr");
      var td = document.createElement("td");
      td.className = "empty";
      td.colSpan = 5;
      td.textContent = "No expenses to show.";
      tr.appendChild(td);
      listEl.appendChild(tr);
    }

    totalEl.textContent = fmt(visibleTotal);

    CATEGORIES.forEach(function (cat) {
      var el = document.querySelector('.cat-total[data-cat="' + cat + '"]');
      if (el) el.textContent = cat + ": " + fmt(catTotals[cat]);
    });
  }

  function remove(id) {
    expenses = expenses.filter(function (e) { return e.id !== id; });
    save();
    render();
  }

  var idCounter = expenses.reduce(function (max, e) {
    return e.id > max ? e.id : max;
  }, 0);

  function nextId() {
    idCounter += 1;
    return idCounter;
  }

  form.addEventListener("submit", function (e) {
    e.preventDefault();
    errorEl.textContent = "";

    var raw = amountEl.value.trim();
    var amount = Number(raw);

    if (raw === "" || isNaN(amount)) {
      errorEl.textContent = "Please enter a valid numeric amount.";
      return;
    }
    if (amount <= 0) {
      errorEl.textContent = "Amount must be greater than zero.";
      return;
    }
    if (!dateEl.value) {
      errorEl.textContent = "Please choose a date.";
      return;
    }

    expenses.push({
      id: nextId(),
      amount: amount,
      category: categoryEl.value,
      date: dateEl.value,
      note: noteEl.value.trim()
    });

    save();
    errorEl.textContent = "";
    amountEl.value = "";
    amountEl.focus();
    render();
  });

  filterCatEl.addEventListener("change", render);
  filterFromEl.addEventListener("change", render);
  filterToEl.addEventListener("change", render);
  filterFromEl.addEventListener("input", render);
  filterToEl.addEventListener("input", render);

  render();
})();
</script>
</body>
</html>
